 16→const (
 17→	defaultSearchLimit     = 10
 18→	maxSearchLimit         = 50
 19→	defaultSearchThreshold = 0.3
 20→)
 21→
 22→// --- search tool ---
 23→
 24→func searchTool() mcpgo.Tool {
 25→	return mcpgo.NewTool("search",
 26→		mcpgo.WithDescription("Search your knowledge base. Returns matching items with titles, types, tags, and content snippets."),
 27→		mcpgo.WithString("query", mcpgo.Required(), mcpgo.Description("Search query text")),
 28→		mcpgo.WithNumber("limit", mcpgo.Description("Max results to return (1-50, default 10)")),
 29→		mcpgo.WithString("type", mcpgo.Description("Filter by item type"), mcpgo.Enum("bookmark", "text_note", "voice_note")),
 30→	)
 31→}
 32→
 33→func searchHandler(deps Deps) server.ToolHandlerFunc {
 34→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
 35→		claims, errResult := requireAuth(ctx)
 36→		if errResult != nil {
 37→			return errResult, nil
 38→		}
 39→
 40→		query := req.GetString("query", "")
 41→		if query == "" {
 42→			return mcpgo.NewToolResultError("query is required"), nil
 43→		}
 44→
 45→		limit := req.GetInt("limit", defaultSearchLimit)
 46→		if limit < 1 {
 47→			limit = 1
 48→		}
 49→		if limit > maxSearchLimit {
 50→			limit = maxSearchLimit
 51→		}
 52→
 53→		var filter *item.Filter
 54→		if t := req.GetString("type", ""); t != "" {
 55→			filter = &item.Filter{Types: []string{t}}
 56→		}
 57→
 58→		result, err := doSearch(ctx, deps, claims.UserID, query, filter, limit)
 59→		if err != nil {
 60→			return mcpgo.NewToolResultError(fmt.Sprintf("search failed: %v", err)), nil
 61→		}
 62→
 63→		return mcpgo.NewToolResultText(formatSearchResults(result)), nil
 64→	}
 65→}
 66→
 67→// doSearch tries semantic search first, falling back to full-text search.
 68→func doSearch(ctx context.Context, deps Deps, ownerID uuid.UUID, query string, filter *item.Filter, limit int) (*item.SearchResult, error) {
 69→	if deps.Embedder != nil {
 70→		embedding, err := deps.Embedder.Embed(ctx, query)
 71→		if err != nil {
 72→			slog.WarnContext(ctx, "mcp: embedding failed, falling back to FTS", "error", err)
 73→		} else {
 74→			result, err := deps.Items.SemanticSearch(ctx, ownerID, embedding, filter, limit, defaultSearchThreshold)
 75→			if err == nil && len(result.Items) > 0 {
 76→				return result, nil
 77→			}
 78→			if err != nil {
 79→				slog.WarnContext(ctx, "mcp: semantic search failed, falling back to FTS", "error", err)
 80→			}
 81→		}
 82→	}
 83→
 84→	return deps.Items.Search(ctx, ownerID, query, filter, limit, 0)
 85→}
