131→func captureHandler(deps Deps) server.ToolHandlerFunc {
132→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
133→		claims, errResult := requireAuth(ctx)
134→		if errResult != nil {
135→			return errResult, nil
136→		}
137→
138→		url := req.GetString("url", "")
139→		content := req.GetString("content", "")
140→		titleStr := req.GetString("title", "")
141→		tagsStr := req.GetString("tags", "")
142→		sensitivity := req.GetString("sensitivity", "normal")
143→
144→		var title *string
145→		if titleStr != "" {
146→			title = &titleStr
147→		}
148→
149→		var tags []string
150→		if tagsStr != "" {
151→			for _, t := range strings.Split(tagsStr, ",") {
152→				t = strings.TrimSpace(t)
153→				if t != "" {
154→					tags = append(tags, t)
155→				}
156→			}
157→		}
158→
159→		switch {
160→		case url != "":
161→			it, err := deps.Items.CaptureBookmark(ctx, claims.UserID, item.BookmarkInput{
162→				URL:         url,
163→				Title:       title,
164→				Tags:        tags,
165→				Sensitivity: sensitivity,
166→				Source:      "mcp",
167→			})
168→			if err != nil {
169→				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture bookmark: %v", err)), nil
170→			}
171→			return mcpgo.NewToolResultText(formatItem(it)), nil
172→
173→		case content != "":
174→			it, err := deps.Items.CaptureNote(ctx, claims.UserID, item.NoteInput{
175→				Title:       title,
176→				Content:     content,
177→				Tags:        tags,
178→				Sensitivity: sensitivity,
179→				Source:      "mcp",
180→			})
181→			if err != nil {
182→				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture note: %v", err)), nil
183→			}
184→			return mcpgo.NewToolResultText(formatItem(it)), nil
185→
186→		default:
187→			return mcpgo.NewToolResultError("either 'url' (for bookmark) or 'content' (for note) is required"), nil
188→		}
189→	}
190→}
